// Animation - Page Loader Home
function initLoaderHome() {

    var tl = gsap.timeline();

    tl.set(".visual-video", {
        opacity: 0,
        filter: "blur(2em)",
        scale: 2,
    }, "0");

    tl.set(".home-header__unfold-svg", {
        yPercent: 100,
        scale: 0.6
    }, "0");

    tl.to(".visual-video", {
        opacity: 0.8,
        ease: "Power3.easeIn",
        duration: durationDefault * 1
    }, "0");

    tl.to(".loading-screen", {
        opacity: 0,
        ease: "Power1.easeIn",
        duration: 0.4,
    }, "0");

    tl.from(".home-loading__volume-p, .home-loading__mews-svg", {
        yPercent: 110,
        ease: "Expo.easeInOut",
        duration: durationDefault * 1.2,
        stagger: 0.3
    }, "< 0.3");

    tl.from(".home-loading__number-left", {
        yPercent: 100,
        ease: "expo-replica",
        duration: durationDefault * 1.666,
    }, "< 0.2");

    tl.fromTo(".home-loading__number-right",
        { yPercent: step },
        {
            yPercent: -(100 - step),
            ease: "expo-replica",  // <-- still your custom ease
            duration: durationDefault * 2.333
        },
        "<"
    );


    tl.fromTo(".home-loading__mews-duplicate", {
        clipPath: "polygon(0% 0%, 0% 0%, 0% 100%, 0% 100%)",
    }, {
        clipPath: "polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%)",
        ease: "expo-replica",
        duration: durationDefault * 2,
    }, `< ${durationDefault * 0.333}`);

    tl.to(".home-loading__number-inner", {
        yPercent: -100,
        ease: "Expo.easeIn",
        duration: durationDefault * 0.8,
    });

    tl.to(".home-loading__volume-p, .home-loading__mews-svg", {
        yPercent: -100,
        ease: "Expo.easeIn",
        duration: durationDefault * 0.8,
    }, "<");

    tl.to(".home-header__unfold-svg", {
        duration: durationDefault * 0.8,
        ease: "Expo.easeOut",
        yPercent: 0,
    }, "< 1");

    tl.to(".home-header__unfold-svg", {
        duration: durationDefault * 1.666,
        ease: "Expo.easeInOut",
        scale: 1,
        clearProps: "all"
    }, "< 0.3");

    tl.to(".visual-video", {
        opacity: 1,
        ease: "Power3.easeInOut",
        filter: "blur(0em)",
        scale: 1,
        duration: durationDefault * 1.666,
        clearProps: "all"
    }, "<");

    tl.from(".nav-logo", {
        y: "-6em",
        // autoAlpha: 0,
        ease: "custom-expo-in",
        duration: durationDefault,
        clearProps: "all",
    }, "<");

    tl.from(".desktop-nav, .btn-hamburger__wrap", {
        y: "-6em",
        // autoAlpha: 0,
        ease: "custom-expo-in",
        duration: durationDefault,
        clearProps: "all",
    }, "< 0.15");

    if (document.querySelector("[data-animation-transition='fade']")) {
        tl.fromTo("[data-animation-transition='fade']", {
            y: "2em",
            rotate: 0.001,
            autoAlpha: 0
        }, {
            y: 0,
            rotate: 0.001,
            autoAlpha: 1,
            ease: "custom-expo-in",
            duration: durationDefault,
            stagger: staggerDefault,
            clearProps: "all"
        }, "< 0.25");
    }

    tl.set(".home-loading", {
        display: "none",
    }, "<");

    tl.call(function () {
        lenis.start();
    }, null, "<");

    // Run Straight away
    tl.call(function () {
        lenis.stop();
        lenis.scrollTo(0, {
            immediate: true,
            force: true,
            lock: true,
            duration: 0.0166
        });
    }, null, 0);

    tl.call(function () {
        lenis.scrollTo(0, {
            immediate: true,
            force: true,
            lock: true,
            duration: 0.0166
        });
    }, null, 0.25);

    tl.call(function () {
        lenis.scrollTo(0, {
            immediate: true,
            force: true,
            lock: true,
            duration: 0.0166
        });
    }, null, 0.5);

    tl.call(function () {
        lenis.scrollTo(0, {
            immediate: true,
            force: true,
            lock: true,
            duration: 0.0166
        });
    }, null, 1);

}

// Animation - Page Loader
function initLoader() {

    var tl = gsap.timeline();

    tl.set(".transition-screen", {
        yPercent: -100,
        rotate: 0.001,
    }, "<");

    tl.to(".loading-screen", {
        opacity: 0,
        duration: 0.3,
        ease: "linear"
    }, "<");

    tl.call(function () {
        lenis.stop();
    }, null, 0);

    tl.call(function () {
        pageTransitionOut();
    }, null, 0.1);

}

// Animation - Page Leave
function pageTransitionIn() {
    var tl = gsap.timeline();

    tl.to(".main-wrap", {
        duration: durationDefault,
        scale: 0.925,
        rotate: 0.001,
        y: "-7.5vh",
        ease: "custom-expo",
        clearProps: "all"
    });

    tl.to(".main-transition-overlay", {
        duration: durationDefault,
        ease: "custom-expo",
        opacity: 0.75,
        clearProps: "all"
    }, "<");

    tl.fromTo(".transition-screen", {
        yPercent: 0,
        rotate: 0.001,
        borderRadius: "5em"
    }, {
        duration: durationDefault,
        yPercent: -100,
        rotate: 0.001,
        borderRadius: "0em",
        ease: "custom-expo",
    }, "<");

    tl.call(function () {
        lenis.stop();
    }, null, 0);
}

// Animation - Page Enter
function pageTransitionOut() {
    var tl = gsap.timeline();

    if (document.querySelector(".home-loading")) {
        tl.set(".home-loading", {
            display: "none",
        }, "<");
    }

    tl.to(".transition-screen", {
        opacity: 0,
        ease: "Power1.easeIn",
        duration: 0.4,
        clearProps: "all"
    }, 0);

    tl.from(".nav-logo", {
        y: "-6em",
        // autoAlpha: 0,
        ease: "custom-expo-in",
        duration: durationDefault,
        clearProps: "all",
    }, 0);

    tl.from(".desktop-nav, .btn-hamburger__wrap", {
        y: "-6em",
        // autoAlpha: 0,
        ease: "custom-expo-in",
        duration: durationDefault,
        clearProps: "all",
    }, 0.15);

    tl.fromTo("[data-animation-transition] .single-word-inner", {
        yPercent: 110,
        rotate: 0.001,
        opacity: 0,
    }, {
        yPercent: 0,
        rotate: 0.001,
        opacity: 1,
        ease: "custom-expo-in",
        duration: durationDefault,
        stagger: staggerDefault,
        clearProps: "all"
    }, 0.15);

    if (document.querySelector(".home-header__unfold-svg")) {
        tl.fromTo(".home-header__unfold-svg", {
            yPercent: 100,
            rotate: 0.001
        }, {
            yPercent: 0,
            rotate: 0.001,
            ease: "custom-expo-in",
            duration: durationDefault,
            clearProps: "all"
        }, 0.3);
    }

    if (document.querySelector("[data-animation-transition='fade']")) {
        tl.fromTo("[data-animation-transition='fade']", {
            y: "2em",
            rotate: 0.001,
            autoAlpha: 0
        }, {
            y: 0,
            rotate: 0.001,
            autoAlpha: 1,
            ease: "custom-expo-in",
            duration: durationDefault,
            stagger: staggerDefault,
            clearProps: "all"
        }, 0.4);
    }

    if (document.querySelector("[data-animation-transition='images']")) {
        tl.fromTo("[data-animation-transition='images'] [data-animation-target='wrap']", {
            scale: 0.75,
            rotate: 0.001,
            autoAlpha: 0
        }, {
            scale: 1,
            rotate: 0.001,
            autoAlpha: 1,
            ease: "custom-expo-in",
            duration: durationDefault,
            stagger: 0.25,
            clearProps: "all"
        }, 0.15);

        tl.fromTo("[data-animation-transition='images'] [data-animation-target='img']", {
            scale: 1.5,
            rotate: 0.001,
        }, {
            scale: 1,
            rotate: 0.001,
            ease: "custom-expo-in",
            duration: durationDefault,
            stagger: 0.25,
            clearProps: "all"
        }, 0.15);
    }

    tl.call(function () {
        lenis.start();
    }, null, 0);

}

function startImageAnimation() {
    // Prevent re-animation if already animated
    if (imagesContainer.classList.contains("animated")) return;
    imagesContainer.classList.add("animated");

    const tl = gsap.timeline();

    tl.fromTo(
        "[data-animation-transition='images'] [data-animation-target='wrap']",
        { scale: 0.75, rotate: 0.001, autoAlpha: 0 },
        { scale: 1, rotate: 0.001, autoAlpha: 1, ease: "power3.out", duration: 1, stagger: 0.25 }
    );

    tl.fromTo(
        "[data-animation-transition='images'] [data-animation-target='img']",
        { scale: 1.5, rotate: 0.001 },
        { scale: 1, rotate: 0.001, ease: "power3.out", duration: 1, stagger: 0.25 },
        0 // align with start of wrap animation
    );
}

function initPageTransitions() {

    // # Common: leave (Before Offset)
    async function commonLeaveBeforeOffset(data) {
        pageTransitionIn(data.current);
        initBasicFunctions();
    }

    // # Common: leave (After Offset)
    async function commonLeaveAfterOffset(data) {
        lenis.destroy();
        killAllScrollTriggers();
        data.current.container.remove();
        $('[data-navigation-status]').attr('data-navigation-status', 'not-active');
        $('[data-scrolling-direction]').attr('data-scrolling-direction', 'down');
        $('[data-scrolling-started]').attr('data-scrolling-started', 'false');
    }

    // # Common: enter
    async function commonEnter(data) {
        initBarbaNavUpdate(data);
        pageTransitionOut(data.next);
    }

    // # Common: beforeEnter
    async function commonBeforeEnter(data) {
        ScrollTrigger.getAll().forEach(t => t.kill());
        // initResetWebflow(data);
        initSmoothScroll(data.next.container);
        initScript();
    }

    // # Common: afterEnter
    async function commonAfterEnter(data) {
        window.scrollTo(0, 0);
        ScrollTrigger.refresh();
        initMiniralsAnimation();
    }

    barba.init({
        sync: true,
        debug: true,
        timeout: 7000,
        preventRunning: true,
        prevent: function ({
            el
        }) {
            if (el.hasAttribute("data-barba-prevent")) {
                return true;
            }
        },
        transitions: [{
            name: 'self',
            async leave(data) {
                await commonLeaveBeforeOffset(data);
                if (data.next) {
                    $('.transition-screen').attr('data-color', $(data.next.container).attr('data-barba-theme'));
                }
                await delay(transitionOffset);
                await commonLeaveAfterOffset(data);
            },
            async enter(data) {
                await commonEnter(data);
            },
            async beforeEnter(data) {
                await commonBeforeEnter(data);
                initMiniralsAnimation();
            },
            async afterEnter(data) {
                await commonAfterEnter(data);
            }
        }, {
            name: 'default',
            once(data) {
                initSmoothScroll(data.next.container);
                initScript();
                initLoader();
            },
            async leave(data) {
                await commonLeaveBeforeOffset(data);
                if ($(data.next.container).attr('data-barba-theme')) {
                    $('.transition-screen').attr('data-color', $(data.next.container).attr('data-barba-theme'));
                }
                await delay(transitionOffset);
                await commonLeaveAfterOffset(data);
            },
            async enter(data) {
                await commonEnter(data);
            },
            async beforeEnter(data) {
                await commonBeforeEnter(data);
                initMiniralsAnimation();
            },
            async afterEnter(data) {
                await commonAfterEnter(data);
                initRegistration();
                initializeChat();
            }
        },
        {
            name: 'home',
            from: {},
            to: {
                namespace: ['home']
            },
            once(data) {
                initSmoothScroll(data.next.container);
                initScript();
                initLoaderHome();
            },
            async leave(data) {
                await commonLeaveBeforeOffset(data);
                if ($(data.next.container).attr('data-barba-theme')) {
                    $('.transition-screen').attr('data-color', $(data.next.container).attr('data-barba-theme'));
                }
                await delay(transitionOffset);
                await commonLeaveAfterOffset(data);
            },
            async enter(data) {
                await commonEnter(data);
            },
            async beforeEnter(data) {
                await commonBeforeEnter(data);
            },
            async afterEnter(data) {
                await commonAfterEnter(data);
            }
        }
        ]
    });


    function initSmoothScroll(container) {
        initLenis();
        ScrollTrigger.refresh();
    }

    // Function to kill all ScrollTrigger data
    function killAllScrollTriggers() {
        if (typeof ScrollTrigger !== 'undefined') {
            ScrollTrigger.killAll(); // Kill all ScrollTrigger instances
        }
    }

    // Reset scroll on page next
    history.scrollRestoration = "manual";
}

function initLenis() {

    // Lenis: https://github.com/studio-freight/lenis
    lenis = new Lenis({
        // duration: 1,
    });

    lenis.on('scroll', ScrollTrigger.update);

    gsap.ticker.add((time) => {
        lenis.raf(time * 1000);
    });

    gsap.ticker.lagSmoothing(0);
}

// Don't touch
function delay(n) {
    n = n || 2000;
    return new Promise((done) => {
        setTimeout(() => {
            done();
        }, n);
    });
}


function initPidwBoard() {
    const boardLocal = [
        'asim-amin', 'justice-zulfiqar-ahmad', 'karamat-ullah-chaudhry', 'shozab-majeed', 'taimur-malik',
    ]
    const boardInternational = [
        'virginie-colauta', 'sherzod', 'tony-andriotis', 'aliaksei-korachkin', 'noor'
    ]

    // crate function to get random board members, one from international and one from local
    function getRandomBoardMembers() {
        const randomLocal = boardLocal[Math.floor(Math.random() * boardLocal.length)];
        const randomInternational = boardInternational[Math.floor(Math.random() * boardInternational.length)];
        return [randomLocal, randomInternational];
    }

    const randomBoardMembers = getRandomBoardMembers();
    console.log(randomBoardMembers);

    $("#board-1").attr("src", `/assets/images/board-member/${randomBoardMembers[0]}.jpg`);
    $("#board-2").attr("src", `/assets/images/board-member/${randomBoardMembers[1]}.jpg`);
}


function initMiniralsAnimation() {
    if (document.querySelector('.sticky-wrap')) {
        $('.sticky-wrap').each(function () {
            let stickyWrap = $(this);
            let triggerElement = $(this).find('.sticky-wrap-invisible');
            let targetElementDarkOverlay = $(this).find('.sticky-wrap-dark-overlay');

            // Function to calculate the offset for the sticky effect
            function calcStickyWrapOffset() {
                let windowHeight = $(window).innerHeight();
                let wrapContentHeight = stickyWrap.find('.sticky-wrap-inner').innerHeight();
                let stickyOffset = (wrapContentHeight - windowHeight);
                stickyWrap.css('--sticky-wrap-offset', Math.round(stickyOffset) + "px");
            }

            // First calculate
            calcStickyWrapOffset();

            $(window).resize(function () {
                // Calculate on resize
                calcStickyWrapOffset();
            });

            let tl = gsap.timeline({
                scrollTrigger: {
                    trigger: triggerElement,
                    start: "0% 100%",
                    end: "0% 0%",
                    scrub: 0,
                    markers: false,
                }
            });

            tl.fromTo(targetElementDarkOverlay, {
                opacity: 0,
            }, {
                duration: 1,
                opacity: 1,
                ease: "none"
            });
        });
    }

    // Header
    if (document.querySelector('.sticky-wrap.is--header')) {
        $('.sticky-wrap.is--header').each(function () {
            let stickyWrap = $(this);
            let triggerElement = $(this).find('.sticky-wrap-invisible');

            let tl = gsap.timeline({
                scrollTrigger: {
                    trigger: triggerElement,
                    start: "0% 100%",
                    end: "0% -140%",
                    scrub: 0,
                    markers: false,
                    toggleActions: "play none none reverse"
                }
            });

            tl.fromTo($(".minerals-intro").find('.pidw-svg path'), {
                yPercent: 150,
            }, {
                duration: 1,
                yPercent: 0,
                stagger: 0.1,
                ease: "Power2.easeOut"
            }, 0);

            var halloScale = 25.5;
            if (window.innerHeight > window.innerWidth) {
                halloScale = 25;
            }

            tl.fromTo($(".minerals-intro").find('.pidw-svg'), {
                scale: 1,
                xPercent: 0,
                yPercent: 0,
            }, {
                duration: 1,
                scale: halloScale,
                xPercent: 150,
                yPercent: -150,
                ease: "Power2.easeIn",
                force3D: true
            }, 0.75);

            tl.fromTo($(".minerals-intro").find('.minerals-intro__logo'), {
                scale: (1 / 15),
                opacity: 0,
            }, {
                duration: 1.2,
                opacity: 1,
                scale: (halloScale / 15),
                ease: "Power2.easeInOut",
            }, 1);

            tl.fromTo(".minerals-intro__logo .word",
                {
                    yPercent: 100,
                    opacity: 0,
                },
                {
                    duration: 0.6,
                    yPercent: 0,
                    opacity: 1,
                    ease: "power2.inOut",
                    stagger: 0.2,
                },
                0.95
            );

            tl.fromTo($(".minerals-intro__logo").find('.tagline'),
                { y: 20, opacity: 0 },
                { y: 0, opacity: 1, ease: "Power2.easeInOut", duration: 0.8 },
                0.95
            );

            tl.to($(".minerals-intro__logo-after"), {
                opacity: 1,
                scale: 1,
                ease: "power2.inOut",
                duration: .5,
                onUpdate: () => {
                    $(".minerals-intro__logo").addClass("bg-visible");
                },
                onReverseComplete: () => {
                    $(".minerals-intro__logo").removeClass("bg-visible");
                }
            }, 1.75);

            tl.to($(".minerals-intro"), {
                backgroundColor: "#fff",
                duration: 0.05,
                ease: "none"
            }, 2.125);

        });
    }

    // Approach
    ScrollTrigger.matchMedia({
        "(min-width: 992px)": function () {
            $('.sticky-wrap.is--approach').each(function () {
                let stickyWrap = $(this);
                let triggerElement = $(this).find('.home-approach');

                let tl = gsap.timeline({
                    scrollTrigger: {
                        trigger: triggerElement,
                        start: "0% 25%",
                        end: "0% -50%",
                        scrub: 0,
                        markers: false,
                    }
                });

                tl.fromTo(stickyWrap.find('.home-approach__col-number'), {
                    yPercent: 150,
                }, {
                    duration: 1,
                    yPercent: 0,
                    stagger: 0.1,
                    ease: "Power2.easeOut"
                }, 0);
            });
        }
    });


    $('.minerals-investment__image').each(function (index, el) {
        const $img = $(el).find('.minerals-investment__image-img');
        if (!$img.length) return;

        // Parallax scroll effect
        gsap.to($img, {
            yPercent: -15,
            ease: "none",
            scrollTrigger: {
                trigger: el,
                start: "top bottom",
                end: "bottom top",
                scrub: 1,
            }
        });

        // Reveal animation on load/scroll into view
        const tl = gsap.timeline({
            scrollTrigger: {
                trigger: el,
                start: "top 85%",
                toggleActions: "play none none reverse",
            }
        });

        // Reveal image (fade + lift + scale)
        tl.fromTo($img,
            { scale: 1.15, opacity: 0, y: 50 },
            { scale: 1, opacity: 1, y: 0, duration: 1.2, ease: "power3.out" },
            0
        );
    });
}

