function initPeaceMandateSlider() {
    $('[data-peace-mandate-slider-init]').each(function () {
        var sliderInit = $(this);
        var nextBtn = sliderInit.find('[data-peace-mandate-slider="next"]');
        var prevBtn = sliderInit.find('[data-peace-mandate-slider="prev"]');
        var sliderThree = sliderInit.find('[data-peace-mandate-slider="three"] [role="list"]');
        var sliderOne = sliderInit.find('[data-peace-mandate-slider="one"] [role="list"]');
        var slidesThree = sliderThree.find('[data-peace-mandate-slide]');
        var slidesOne = sliderOne.find('[data-peace-mandate-slide]');

        var isAnimating = false;
        var currentIndex = 0;

        // Calculate total number of slides before cloning
        var totalSlides = slidesThree.length;

        // Format totalSlides as a two-digit number
        var totalSlidesFormatted = totalSlides < 10 ? '0' + totalSlides : totalSlides.toString();

        // Set the formatted total to the element with [data-peace-mandate-slider="total"]
        sliderInit.find('[data-peace-mandate-slider="total"]').text(totalSlidesFormatted);

        // Clone slides to make the slider infinite
        var loopSlides = 2; // Number of slides to clone at each end for looping

        // Clone slides for 'three' slider
        slidesThree.slice(0, loopSlides).clone(true).addClass('clone').appendTo(sliderThree);
        slidesThree.slice(-loopSlides).clone(true).addClass('clone').prependTo(sliderThree);

        // Update slidesThree after cloning
        slidesThree = sliderThree.find('[data-peace-mandate-slide]');
        // Adjust currentIndex to account for cloned slides
        currentIndex += loopSlides;

        // Similarly clone slides for 'one' slider
        slidesOne.slice(0, loopSlides).clone(true).addClass('clone').appendTo(sliderOne);
        slidesOne.slice(-loopSlides).clone(true).addClass('clone').prependTo(sliderOne);

        // Update slidesOne after cloning
        slidesOne = sliderOne.find('[data-peace-mandate-slide]');

        // Function to calculate cumulative positions of slides
        function getSlidePositions(slides) {
            var positions = [0]; // Start with 0
            slides.each(function (i) {
                var slideHeight = $(this).outerHeight(true);
                positions.push(positions[i] + slideHeight);
            });
            return positions;
        }

        // Function to calculate center positions for centering slides
        function getCenterPositions(slides, positions) {
            var centerPositions = [];
            slides.each(function (i) {
                var slideHeight = $(this).outerHeight(true);
                var slideCenterOffset = positions[i] + (slideHeight / 2);
                var translateY = (sliderInit.find('[data-peace-mandate-slider="height"]').height() / 2) - slideCenterOffset;
                centerPositions.push(translateY);
            });
            return centerPositions;
        }

        // Get positions and center positions for both sliders
        var positionsThree = getSlidePositions(slidesThree);
        var positionsOne = getSlidePositions(slidesOne);

        var centerPositionsThree = getCenterPositions(slidesThree, positionsThree);

        // Set the initial position of sliderThree and sliderOne
        gsap.set(sliderThree, { y: centerPositionsThree[currentIndex] });
        gsap.set(sliderOne, { y: -positionsOne[currentIndex] });

        // Update the active class on the center slide
        function updateActiveClass() {
            // Remove active class from all slides
            slidesThree.removeClass('is--active');
            slidesOne.removeClass('is--active');

            // Calculate real index within original slides
            var realIndex = (currentIndex - loopSlides) % totalSlides;
            if (realIndex < 0) realIndex += totalSlides;

            // Apply active class to both original and cloned slides
            slidesThree.each(function (i) {
                var slide = $(this);
                var indexInOriginal = (i - loopSlides) % totalSlides;
                if (indexInOriginal < 0) indexInOriginal += totalSlides;
                if (indexInOriginal === realIndex) {
                    slide.addClass('is--active');
                }
            });

            slidesOne.each(function (i) {
                var slide = $(this);
                var indexInOriginal = (i - loopSlides) % totalSlides;
                if (indexInOriginal < 0) indexInOriginal += totalSlides;
                if (indexInOriginal === realIndex) {
                    slide.addClass('is--active');
                }
            });
        }

        // Function to slide to a specific index
        function slideTo(index) {
            if (isAnimating) return;
            isAnimating = true;

            // Update currentIndex before starting the animation
            currentIndex = index;

            // Update the active class immediately
            updateActiveClass();

            // Recalculate positions and center positions in case slide heights have changed
            positionsThree = getSlidePositions(slidesThree);
            positionsOne = getSlidePositions(slidesOne);
            centerPositionsThree = getCenterPositions(slidesThree, positionsThree);

            // Animate with GSAP
            var timeline = gsap.timeline({
                onComplete: function () {
                    isAnimating = false;

                    // Handle infinite looping
                    if (currentIndex < loopSlides) {
                        // Jump to the corresponding real slide at the end
                        currentIndex += totalSlides;
                        gsap.set([sliderThree, sliderOne], {
                            y: function (i, target) {
                                return target === sliderThree.get(0)
                                    ? centerPositionsThree[currentIndex]
                                    : -positionsOne[currentIndex];
                            }
                        });
                        // No need to update the active class here as we already did
                    } else if (currentIndex >= totalSlides + loopSlides) {
                        // Jump to the corresponding real slide at the beginning
                        currentIndex -= totalSlides;
                        gsap.set([sliderThree, sliderOne], {
                            y: function (i, target) {
                                return target === sliderThree.get(0)
                                    ? centerPositionsThree[currentIndex]
                                    : -positionsOne[currentIndex];
                            }
                        });
                        // No need to update the active class here as we already did
                    }
                }
            });

            // Animate to the new position
            timeline.to([sliderThree, sliderOne], {
                y: function (i, target) {
                    return target === sliderThree.get(0)
                        ? centerPositionsThree[currentIndex]
                        : -positionsOne[currentIndex];
                },
                duration: 1,
                ease: 'primary-ease'
            });
        }

        // Initial call to set the active class
        updateActiveClass();

        // Next button event listener
        nextBtn.on('click', function () {
            slideTo(currentIndex + 1);
        });

        // Prev button event listener
        prevBtn.on('click', function () {
            slideTo(currentIndex - 1);
        });

        // Add click event listeners to the slides
        slidesThree.on('click', function () {
            var clickedIndex = slidesThree.index(this);

            // Prevent interaction if animation is in progress or clicked slide is already active
            if (isAnimating || clickedIndex === currentIndex) return;

            // Slide to the clicked slide
            slideTo(clickedIndex);
        });
    });
}